const recs       = $('Supabase — Week Recommendations').all().map(i => i.json);
const treasury   = $('Supabase — Latest Treasury').first().json || {};
const leadStats  = $('Supabase — Lead Stats').first().json || {};
const dealStats  = $('Supabase — Deal Stats').first().json || {};
const ragRows    = $('Supabase — Brief RAG Patterns').all().map(i => i.json);

const currency = treasury.currency || 'USD';
const fmt = n => parseFloat(n || 0).toLocaleString('en-US', { maximumFractionDigits: 0 });

// Group recs by priority
const critical = recs.filter(r => r.priority === 'CRITICAL');
const high     = recs.filter(r => r.priority === 'HIGH');
const medium   = recs.filter(r => r.priority === 'MEDIUM');

const formatRec = r => {
  let data = {};
  try { data = typeof r.data === 'string' ? JSON.parse(r.data) : r.data || {}; } catch(e) {}
  const summary = data.action || data.explanation || data.recommendation || data.full_analysis || JSON.stringify(data).substring(0, 150);
  return `[${r.agent}/${r.rec_type}] ${summary}`;
};

const ragExamples = ragRows.map((r, i) => {
  const m = r.metadata || {};
  return `Style example ${i+1} (well-received brief):\n${r.content?.substring(0, 300) || 'N/A'}`;
}).join('\n\n') || 'No past brief examples yet.';

const weekStart = new Date();
weekStart.setDate(weekStart.getDate() - 6);

const context = [
  `=== BRIEF PERIOD: ${weekStart.toDateString()} – ${new Date().toDateString()} ===`,
  '',
  '=== TREASURY ===',
  `Runway: ${treasury.runway_months || 'N/A'} months (${treasury.alert_level || 'UNKNOWN'})`,
  `Cash: ${currency} ${fmt(treasury.cash)}  |  Burn: ${currency} ${fmt(treasury.burn_rate)}/mo`,
  `Safe growth budget: ${currency} ${fmt(treasury.safe_budget)}`,
  treasury.warnings?.length ? `Data warnings: ${(treasury.warnings || []).join('; ')}` : '',
  '',
  '=== LEADS THIS WEEK ===',
  `New: ${leadStats.total_leads || 0}  |  Hot: ${leadStats.hot_leads || 0}  |  Warm: ${leadStats.warm_leads || 0}  |  Replied: ${leadStats.replied_leads || 0}`,
  '',
  '=== PIPELINE ===',
  `Stuck deals: ${dealStats.stuck_count || 0}  |  Stuck value: ${currency} ${fmt(dealStats.stuck_value)}`,
  '',
  '=== CRITICAL ITEMS THIS WEEK ===',
  critical.length > 0 ? critical.slice(0, 3).map(formatRec).join('\n') : 'None',
  '',
  '=== HIGH PRIORITY ITEMS ===',
  high.length > 0 ? high.slice(0, 5).map(formatRec).join('\n') : 'None',
  '',
  '=== MEDIUM ITEMS ===',
  medium.length > 0 ? medium.slice(0, 3).map(formatRec).join('\n') : 'None',
  '',
  '=== PREVIOUS BRIEF STYLE EXAMPLES ===',
  ragExamples
].filter(l => l !== undefined).join('\n');

const prompt = `You are a Chief of Staff writing the weekly executive brief for a founder.

Your brief must:
- Be actionable, not informational
- Lead with the most urgent item
- Use specific numbers
- Max 5 bullet points total
- Each bullet: [DOMAIN] What happened → Why it matters → What to do TODAY
- Domains: TREASURY | PIPELINE | LEADS | CASH | SPEND
- Never use: synergy, leverage, optimize, streamline, paradigm
- If everything is healthy, say so in 2 bullets and identify one growth opportunity

DATA:
${context}`;

return [{
  json: {
    _brief_prompt: prompt,
    _meta: {
      rec_counts: { critical: critical.length, high: high.length, medium: medium.length },
      lead_stats: leadStats,
      deal_stats: dealStats,
      treasury: { runway_months: treasury.runway_months, alert_level: treasury.alert_level, currency }
    }
  }
}];

const meta     = $('Build Brief Context (UC8)').first().json._meta;
const validated = $input.first().json;
const rawText   = $('Claude — Generate Brief').first().json.content?.[0]?.text || '';

const briefText = validated.valid ? validated.output : rawText;
const t  = meta.treasury || {};
const ls = meta.lead_stats || {};
const ds = meta.deal_stats || {};
const cnt = meta.rec_counts || {};
const curr = t.currency || 'USD';

const alertEmoji = t.alert_level === 'CRITICAL' ? '🚨' : t.alert_level === 'WARNING' ? '⚠️' : '✅';
const today = new Date().toLocaleDateString('en-GB', { weekday: 'long', day: 'numeric', month: 'short', year: 'numeric' });

const slackHeader = [
  `🧠 *Weekly Revenue OS Brief — ${today}*`,
  `${alertEmoji} Runway: *${t.runway_months || 'N/A'} months* (${t.alert_level || '?'})  ·  Leads this week: *${ls.total_leads || 0}* (${ls.hot_leads || 0} hot)  ·  Stuck deals: *${ds.stuck_count || 0}*`,
  `Critical items: ${cnt.critical || 0}  |  High priority: ${cnt.high || 0}`,
  ''
].join('\n');

const slackMessage = slackHeader + briefText;

const emailHtml = `<html><body style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 20px;">
<h2 style="color: #1a1a2e;">📊 Weekly Revenue OS Brief</h2>
<p style="color: #666;">${today}</p>
<hr/>
<h3>Summary</h3>
<pre style="white-space: pre-wrap; font-family: Arial; background: #f5f5f5; padding: 15px; border-radius: 5px;">${briefText}</pre>
<hr/>
<h3>Key Metrics</h3>
<table style="width:100%; border-collapse: collapse;">
<tr><td style="padding: 8px; border: 1px solid #ddd;">Runway</td><td style="padding: 8px; border: 1px solid #ddd;"><strong>${t.runway_months || 'N/A'} months</strong></td></tr>
<tr><td style="padding: 8px; border: 1px solid #ddd;">New Leads</td><td style="padding: 8px; border: 1px solid #ddd;">${ls.total_leads || 0} (${ls.hot_leads || 0} hot)</td></tr>
<tr><td style="padding: 8px; border: 1px solid #ddd;">Stuck Deals</td><td style="padding: 8px; border: 1px solid #ddd;">${ds.stuck_count || 0}</td></tr>
</table>
</body></html>`;

return [{ json: { brief_text: briefText, slack_message: slackMessage, email_html: emailHtml, meta } }];
